SELECT SUM(goals) AS total_goals_scored
FROM scorers
WHERE season_id = 0;

SELECT team_name, attendance
FROM teams
WHERE attendance > (SELECT AVG(attendance) FROM teams);

SELECT player_id, goals
FROM players
ORDER BY goals DESC;

SELECT SUM(transfer_fee) AS total_loan_transfer_fee
FROM transfers
WHERE transfer_type = 'Loan';

SELECT transfer_fee
FROM transfers
WHERE strftime('%Y', transfer_date) = '1996';
